<?php namespace App\Http\Controllers;
use App\Models\User; use App\Services\JwtService; use Illuminate\Http\Request; use Illuminate\Support\Facades\Hash;
class AuthController extends Controller { public function login(Request $r,JwtService $jwt){$d=$r->validate(['email'=>'required|email','password'=>'required']);$u=User::with('role','employee.area')->where('email',$d['email'])->first();if(!$u||!Hash::check($d['password'],$u->password)||!$u->active)return response()->json(['message'=>'Credenciales inválidas'],401);return ['token'=>$jwt->issue($u),'token_type'=>'Bearer','user'=>$u];} public function me(Request $r){return $r->user()->load('role','employee.area');} public function logout(){return response()->json(['message'=>'Sesión cerrada; elimine el token del cliente']);} }
